import React, { useState, useEffect } from 'react';
import axios from 'axios';
import { LogIn, Mail, Lock, LogOut, ShieldCheck, FileText, Activity, UserPlus, Plus, X, CheckCircle } from 'lucide-react';

const Login = () => {
  const [isRegistering, setIsRegistering] = useState(false);
  const [formData, setFormData] = useState({ name: '', email: '', password: '' });
  const [message, setMessage] = useState('');
  const [isLoggedIn, setIsLoggedIn] = useState(false);
  const [isLoading, setIsLoading] = useState(false);
  const [showModal, setShowModal] = useState(false); // For "Add License" Popup
  const [licenseCount, setLicenseCount] = useState(4); // Dynamic count

  useEffect(() => {
    const token = localStorage.getItem('token');
    if (token) setIsLoggedIn(true);
  }, []);

  const handleAuth = async (e) => {
    e.preventDefault();
    setIsLoading(true);
    const url = isRegistering ? 'register' : 'login';
    try {
      const res = await axios.post(`http://localhost:5000/api/auth/${url}`, formData);
      if (!isRegistering) {
        localStorage.setItem('token', res.data.token);
        localStorage.setItem('userName', res.data.user.name);
        setIsLoggedIn(true);
      } else {
        setMessage('✅ Account created! Please log in.');
        setIsRegistering(false);
      }
    } catch (err) {
      setMessage(err.response?.data?.msg || 'Action Failed');
    }
    setIsLoading(false);
  };

  const handleAddLicense = (e) => {
    e.preventDefault();
    setLicenseCount(prev => prev + 1);
    setShowModal(false);
    alert("License Added to Queue!");
  };

  const handleLogout = () => {
    localStorage.clear();
    setIsLoggedIn(false);
  };

  if (isLoggedIn) {
    return (
      <div className="min-h-screen bg-slate-50 flex flex-col font-sans">
        {/* Navbar */}
        <nav className="bg-white shadow-sm border-b p-4 sticky top-0 z-50">
          <div className="max-w-7xl mx-auto flex justify-between items-center">
            <h1 className="text-xl font-black text-blue-600 tracking-tight italic">QUAD SOLUTIONS</h1>
            <button onClick={handleLogout} className="text-red-500 flex items-center gap-2 font-bold hover:bg-red-50 px-3 py-1 rounded-lg transition">
              <LogOut size={18} /> Logout
            </button>
          </div>
        </nav>

        <main className="p-4 md:p-10 max-w-7xl mx-auto w-full">
          <div className="flex flex-col md:flex-row justify-between items-start md:items-center mb-10 gap-4">
            <div>
              <h2 className="text-3xl font-extrabold text-slate-900">Healthcare Dashboard</h2>
              <p className="text-slate-500">Welcome, {localStorage.getItem('userName')} • Status: <span className="text-green-600 font-bold">Verified</span></p>
            </div>
            <button 
              onClick={() => setShowModal(true)}
              className="bg-blue-600 text-white px-6 py-3 rounded-2xl font-bold shadow-lg shadow-blue-200 hover:bg-blue-700 flex items-center gap-2 transform active:scale-95 transition"
            >
              <Plus size={20} /> Add New License
            </button>
          </div>

          {/* DASHBOARD CARDS */}
          <div className="grid grid-cols-1 md:grid-cols-3 gap-6 mb-10">
            <div className="bg-white p-8 rounded-3xl shadow-sm border border-slate-100 relative overflow-hidden group">
              <div className="absolute top-0 right-0 w-24 h-24 bg-blue-50 rounded-bl-full -mr-12 -mt-12 group-hover:w-32 group-hover:h-32 transition-all"></div>
              <ShieldCheck className="text-blue-600 mb-4" size={32} />
              <h3 className="text-slate-400 font-bold uppercase text-xs tracking-widest">Active Licenses</h3>
              <p className="text-4xl font-black text-slate-900 mt-1">{licenseCount.toString().padStart(2, '0')}</p>
            </div>
            
            <div className="bg-white p-8 rounded-3xl shadow-sm border border-slate-100 relative overflow-hidden group">
              <div className="absolute top-0 right-0 w-24 h-24 bg-emerald-50 rounded-bl-full -mr-12 -mt-12"></div>
              <FileText className="text-emerald-500 mb-4" size={32} />
              <h3 className="text-slate-400 font-bold uppercase text-xs tracking-widest">Certifications</h3>
              <p className="text-4xl font-black text-slate-900 mt-1">12</p>
            </div>

            <div className="bg-white p-8 rounded-3xl shadow-sm border border-slate-100 relative overflow-hidden group">
              <div className="absolute top-0 right-0 w-24 h-24 bg-orange-50 rounded-bl-full -mr-12 -mt-12"></div>
              <Activity className="text-orange-500 mb-4" size={32} />
              <h3 className="text-slate-400 font-bold uppercase text-xs tracking-widest">Compliance Score</h3>
              <p className="text-4xl font-black text-emerald-600 mt-1">92%</p>
            </div>
          </div>

          <div className="bg-blue-900 rounded-3xl p-8 text-white flex flex-col md:flex-row items-center justify-between shadow-xl">
             <div className="mb-4 md:mb-0">
               <h3 className="text-xl font-bold mb-1">Credentialing Health Check</h3>
               <p className="text-blue-200 text-sm">You have 2 items expiring in the next 30 days. Action required.</p>
             </div>
             <button className="bg-white text-blue-900 px-6 py-2 rounded-xl font-bold hover:bg-blue-50 transition">Review Now</button>
          </div>
        </main>

        {/* --- ADD LICENSE MODAL (POPUP) --- */}
        {showModal && (
          <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-sm flex items-center justify-center p-4 z-[100]">
            <div className="bg-white w-full max-w-md rounded-3xl shadow-2xl overflow-hidden animate-in fade-in zoom-in duration-200">
              <div className="bg-blue-600 p-6 flex justify-between items-center text-white">
                <h3 className="text-xl font-bold flex items-center gap-2"><Plus size={24}/> New Credential</h3>
                <button onClick={() => setShowModal(false)} className="hover:rotate-90 transition"><X size={24}/></button>
              </div>
              <form onSubmit={handleAddLicense} className="p-8 space-y-4">
                <div>
                  <label className="block text-sm font-bold text-slate-700 mb-1">License Type</label>
                  <input type="text" placeholder="e.g. Registered Nurse" className="w-full p-3 rounded-xl bg-slate-50 border-none focus:ring-2 focus:ring-blue-500" required />
                </div>
                <div>
                  <label className="block text-sm font-bold text-slate-700 mb-1">License Number</label>
                  <input type="text" placeholder="e.g. LIC-998877" className="w-full p-3 rounded-xl bg-slate-50 border-none focus:ring-2 focus:ring-blue-500" required />
                </div>
                <button className="w-full bg-blue-600 text-white py-4 rounded-2xl font-bold text-lg hover:bg-blue-700 transition mt-4">
                  Confirm & Submit
                </button>
              </form>
            </div>
          </div>
        )}
      </div>
    );
  }

  // --- LOGIN VIEW ---
  return (
    <div className="flex items-center justify-center min-h-screen bg-slate-100 p-4">
      <div className="w-full max-w-md bg-white p-10 rounded-[2.5rem] shadow-2xl border-t-8 border-blue-600">
        <div className="text-center mb-8">
          <div className="inline-block p-4 bg-blue-50 rounded-full text-blue-600 mb-4 animate-bounce">
            {isRegistering ? <UserPlus size={32} /> : <LogIn size={32} />}
          </div>
          <h2 className="text-4xl font-black text-slate-900">{isRegistering ? "Join Us" : "Login"}</h2>
          <p className="text-slate-500 mt-1 font-medium italic">Credentialing for Modern Teams</p>
        </div>

        <form onSubmit={handleAuth} className="space-y-4">
          {isRegistering && (
            <input type="text" placeholder="Full Name" className="w-full px-5 py-4 rounded-2xl bg-slate-50 border-transparent focus:bg-white focus:border-blue-500 focus:ring-0 transition font-medium"
              onChange={(e) => setFormData({...formData, name: e.target.value})} required />
          )}
          <input type="email" placeholder="Work Email" className="w-full px-5 py-4 rounded-2xl bg-slate-50 border-transparent focus:bg-white focus:border-blue-500 focus:ring-0 transition font-medium"
            onChange={(e) => setFormData({...formData, email: e.target.value})} required />
          <input type="password" placeholder="Password" className="w-full px-5 py-4 rounded-2xl bg-slate-50 border-transparent focus:bg-white focus:border-blue-500 focus:ring-0 transition font-medium"
            onChange={(e) => setFormData({...formData, password: e.target.value})} required />
          
          <button 
            disabled={isLoading}
            className={`w-full ${isLoading ? 'bg-slate-400' : 'bg-blue-600'} py-4 rounded-2xl text-white font-bold text-xl hover:bg-blue-700 shadow-xl shadow-blue-100 transition transform active:scale-95`}
          >
            {isLoading ? "Verifying..." : (isRegistering ? "Create My Account" : "Access Dashboard")}
          </button>
        </form>

        <button onClick={() => setIsRegistering(!isRegistering)} className="w-full mt-8 text-sm font-bold text-slate-400 hover:text-blue-600 transition flex items-center justify-center gap-2">
          {isRegistering ? "I already have an account" : "New to QuadSolutions? Create an account"}
        </button>

        {message && (
          <div className={`mt-6 p-4 rounded-2xl text-center font-bold text-sm ${message.includes('✅') ? 'bg-emerald-50 text-emerald-600' : 'bg-red-50 text-red-600'}`}>
            {message}
          </div>
        )}
      </div>
    </div>
  );
};

export default Login;
